@Service
public class AnticheatDebugLogService implements Listener {
  private static final String UNKNOWN = "unknown";
  private static final NamespacedKey SELECTED_CHARACTER_KEY = NamespacedKey.fromString("characters:selected_character");
  private static final long BUFFER_WINDOW_MILLIS = 10_000;
  private static final long FEATURE_WINDOW_MILLIS = 5_000;
  private static final int MAX_SAMPLES_PER_PLAYER = 120;
  private static final int MAX_EVENTS_PER_PLAYER = 40;
  private static final long SAMPLE_PERIOD_TICKS = 4;

  private final Map<String, PlayerDebugBuffer> buffers = new HashMap<>();

  @EventListener
  void onEnable(PluginEnableEvent event) {
    Plugin plugin = Bukkit.getPluginManager().getPlugin("PaperCommonsBundle");
    if (plugin == null) return;

    Bukkit.getScheduler().runTaskTimer(plugin, () -> {
      for (Player player : Bukkit.getOnlinePlayers()) {
        sample(player);
      }
    }, SAMPLE_PERIOD_TICKS, SAMPLE_PERIOD_TICKS);
  }

  @EventHandler
  void onQuit(PlayerQuitEvent event) {
    buffers.remove(event.getPlayer().getName());
  }

  @EventHandler
  void onVelocity(PlayerVelocityEvent event) {
    Player player = event.getPlayer();
    Vector velocity = event.getVelocity();
    recordEvent(player.getName(), "velocity", new JsonObject()
      .add("x", velocity.getX())
      .add("y", velocity.getY())
      .add("z", velocity.getZ())
      .toString());
    sample(player);
  }

  @EventHandler
  void onTeleport(PlayerTeleportEvent event) {
    Player player = event.getPlayer();
    Location from = event.getFrom();
    Location to = event.getTo();

    recordEvent(player.getName(), "teleport", new JsonObject()
      .addRaw("from", locationJson(from))
      .addRaw("to", locationJson(to))
      .add("cause", event.getCause().name())
      .toString());
    sample(player);
  }

  public String store(Player player, String sender, String reasonKey, double vl) {
    AnticheatDebugLogDTO dto = createDto(player, sender, reasonKey, vl);
    ClickHouseProvider.get().publish(dto);
    return dto.getLogId();
  }

  private AnticheatDebugLogDTO createDto(Player player, String sender, String reasonKey, double vl) {
    Location location = player.getLocation();
    Vector velocity = player.getVelocity();
    BufferSnapshot bufferSnapshot = snapshot(player.getName(), System.currentTimeMillis());

    AnticheatDebugLogDTO dto = new AnticheatDebugLogDTO();
    dto.setLogId(UUID.randomUUID().toString());
    dto.setServer(ServerIdentityProvider.identity == null ? UNKNOWN : ServerIdentityProvider.identity);
    dto.setPlayer(player.getName());
    dto.setSender(sender == null ? UNKNOWN : sender);
    dto.setReasonKey(normalizeReason(reasonKey));
    dto.setVl(vl);

    dto.setWorld(location.getWorld() == null ? UNKNOWN : location.getWorld().getName());
    dto.setX(location.x());
    dto.setY(location.y());
    dto.setZ(location.z());
    dto.setYaw(location.getYaw());
    dto.setPitch(location.getPitch());

    dto.setGameMode(player.getGameMode().name());
    dto.setCharacter(selectedCharacter(player));
    dto.setPing(player.getPing());
    dto.setTps(Bukkit.getTPS()[0]);
    dto.setMspt(Bukkit.getAverageTickTime());

    dto.setVelocityX(velocity.getX());
    dto.setVelocityY(velocity.getY());
    dto.setVelocityZ(velocity.getZ());
    dto.setHorizontalSpeed(Math.sqrt(velocity.getX() * velocity.getX() + velocity.getZ() * velocity.getZ()));
    dto.setVerticalSpeed(velocity.getY());

    dto.setOnGround(player.isOnGround());
    dto.setSprinting(player.isSprinting());
    dto.setSneaking(player.isSneaking());
    dto.setSwimming(player.isSwimming());
    dto.setFlying(player.isFlying());
    dto.setGliding(player.isGliding());
    dto.setInsideVehicle(player.isInsideVehicle());

    dto.setBlockBelow(blockType(location.clone().subtract(0, 1, 0).getBlock()));
    dto.setBlockFeet(blockType(location.getBlock()));
    dto.setBlockHead(blockType(location.clone().add(0, 1, 0).getBlock()));

    dto.setMovementSpeedAttribute(attributeValue(player, "minecraft:movement_speed"));
    dto.setFlyingSpeedAttribute(attributeValue(player, "minecraft:flying_speed"));
    dto.setJumpStrengthAttribute(attributeValue(player, "minecraft:jump_strength"));
    dto.setGravityAttribute(attributeValue(player, "minecraft:gravity"));
    dto.setStepHeightAttribute(attributeValue(player, "minecraft:step_height"));
    dto.setScaleAttribute(attributeValue(player, "minecraft:scale"));

    dto.setSpeedEffectAmplifier(effectAmplifier(player, PotionEffectType.SPEED));
    dto.setJumpEffectAmplifier(effectAmplifier(player, PotionEffectType.JUMP_BOOST));
    dto.setHasLevitation(player.hasPotionEffect(PotionEffectType.LEVITATION));
    dto.setHasSlowFalling(player.hasPotionEffect(PotionEffectType.SLOW_FALLING));
    dto.setHasDolphinsGrace(player.hasPotionEffect(PotionEffectType.DOLPHINS_GRACE));

    dto.setSamplesCount(bufferSnapshot.samplesCount());
    dto.setMaxHorizontalSpeed5s(bufferSnapshot.maxHorizontalSpeed());
    dto.setAvgHorizontalSpeed5s(bufferSnapshot.avgHorizontalSpeed());
    dto.setP95HorizontalSpeed5s(bufferSnapshot.p95HorizontalSpeed());
    dto.setMaxVerticalSpeed5s(bufferSnapshot.maxVerticalSpeed());
    dto.setMaxPing5s(bufferSnapshot.maxPing());
    dto.setMaxMspt5s(bufferSnapshot.maxMspt());
    dto.setGroundStateChanges5s(bufferSnapshot.groundStateChanges());
    dto.setBlockBelowChanges5s(bufferSnapshot.blockBelowChanges());
    dto.setHadRecentVelocity(bufferSnapshot.hadRecentVelocity());
    dto.setHadRecentTeleport(bufferSnapshot.hadRecentTeleport());
    dto.setMsSinceLastVelocity(bufferSnapshot.msSinceLastVelocity());
    dto.setMsSinceLastTeleport(bufferSnapshot.msSinceLastTeleport());

    dto.setAttributesJson(attributesJson(player));
    dto.setEffectsJson(effectsJson(player.getActivePotionEffects()));
    dto.setEquipmentJson(equipmentJson(player.getEquipment()));
    dto.setEnvironmentJson(environmentJson(location));
    dto.setCharacteristicsJson(characteristicsJson(player.getPersistentDataContainer()));
    dto.setFlagsJson(flagsJson(player));
    dto.setMovementSamplesJson(bufferSnapshot.samplesJson());
    dto.setRecentEventsJson(bufferSnapshot.eventsJson());

    return dto;
  }

  private void sample(Player player) {
    long now = System.currentTimeMillis();
    Location location = player.getLocation();
    Vector velocity = player.getVelocity();

    MovementSample sample = new MovementSample(
      now,
      location.x(),
      location.y(),
      location.z(),
      velocity.getX(),
      velocity.getY(),
      velocity.getZ(),
      Math.sqrt(velocity.getX() * velocity.getX() + velocity.getZ() * velocity.getZ()),
      velocity.getY(),
      player.isOnGround(),
      player.isSprinting(),
      player.isSwimming(),
      player.isFlying(),
      player.isGliding(),
      player.isInsideVehicle(),
      blockType(location.clone().subtract(0, 1, 0).getBlock()),
      blockType(location.getBlock()),
      player.getPing(),
      Bukkit.getTPS()[0],
      Bukkit.getAverageTickTime()
    );

    PlayerDebugBuffer buffer = buffer(player.getName());
    buffer.samples.addLast(sample);
    trim(buffer, now);
  }

  private void recordEvent(String player, String type, String payloadJson) {
    long now = System.currentTimeMillis();
    PlayerDebugBuffer buffer = buffer(player);
    buffer.events.addLast(new DebugEvent(now, type, payloadJson));
    trim(buffer, now);
  }

  private PlayerDebugBuffer buffer(String player) {
    return buffers.computeIfAbsent(player, __ -> new PlayerDebugBuffer());
  }

  private void trim(PlayerDebugBuffer buffer, long now) {
    while (!buffer.samples.isEmpty() && (now - buffer.samples.peekFirst().timeMillis > BUFFER_WINDOW_MILLIS || buffer.samples.size() > MAX_SAMPLES_PER_PLAYER)) {
      buffer.samples.removeFirst();
    }

    while (!buffer.events.isEmpty() && (now - buffer.events.peekFirst().timeMillis > BUFFER_WINDOW_MILLIS || buffer.events.size() > MAX_EVENTS_PER_PLAYER)) {
      buffer.events.removeFirst();
    }
  }

  private BufferSnapshot snapshot(String player, long now) {
    PlayerDebugBuffer buffer = buffers.get(player);
    if (buffer == null) return BufferSnapshot.empty();

    trim(buffer, now);

    List<MovementSample> samples = buffer.samples.stream()
      .filter(sample -> now - sample.timeMillis <= FEATURE_WINDOW_MILLIS)
      .toList();
    List<DebugEvent> events = buffer.events.stream()
      .filter(event -> now - event.timeMillis <= FEATURE_WINDOW_MILLIS)
      .toList();

    return BufferSnapshot.from(samples, events, now);
  }

  private String normalizeReason(String reasonKey) {
    if (reasonKey == null || reasonKey.isBlank()) return UNKNOWN;
    return reasonKey.trim().toLowerCase(Locale.ROOT).replaceAll("[^a-z0-9_.:-]", "_");
  }

  private String selectedCharacter(Player player) {
    if (SELECTED_CHARACTER_KEY == null) return UNKNOWN;
    String character = player.getPersistentDataContainer().get(SELECTED_CHARACTER_KEY, PersistentDataType.STRING);
    return character == null || character.isBlank() ? UNKNOWN : character;
  }

  private double attributeValue(Player player, String key) {
    try {
      NamespacedKey namespacedKey = NamespacedKey.fromString(key);
      if (namespacedKey == null) return 0;

      Attribute attribute = Registry.ATTRIBUTE.get(namespacedKey);
      if (attribute == null) return 0;

      AttributeInstance instance = player.getAttribute(attribute);
      return instance == null ? 0 : instance.getValue();
    } catch (Exception ignored) {
      return 0;
    }
  }

  private int effectAmplifier(Player player, PotionEffectType type) {
    PotionEffect effect = player.getPotionEffect(type);
    return effect == null ? -1 : effect.getAmplifier();
  }

  private String blockType(Block block) {
    return block.getType().getKey().asString();
  }

  private String locationJson(Location location) {
    if (location == null) return "null";

    return new JsonObject()
      .add("world", location.getWorld() == null ? UNKNOWN : location.getWorld().getName())
      .add("x", location.x())
      .add("y", location.y())
      .add("z", location.z())
      .add("yaw", location.getYaw())
      .add("pitch", location.getPitch())
      .toString();
  }

  private String attributesJson(Player player) {
    JsonArray attributes = new JsonArray();

    for (Attribute attribute : Registry.ATTRIBUTE) {
      AttributeInstance instance = player.getAttribute(attribute);
      if (instance == null) continue;

      JsonObject object = new JsonObject()
        .add("attribute", attribute.translationKey())
        .add("base", instance.getBaseValue())
        .add("value", instance.getValue());

      JsonArray modifiers = new JsonArray();
      for (AttributeModifier modifier : instance.getModifiers()) {
        modifiers.add(new JsonObject()
                        .add("key", modifier.getKey().asString())
                        .add("amount", modifier.getAmount())
                        .add("operation", modifier.getOperation().name()));
      }
      object.addRaw("modifiers", modifiers.toString());
      attributes.add(object);
    }

    return attributes.toString();
  }

  private String effectsJson(Collection<PotionEffect> effects) {
    JsonArray result = new JsonArray();

    for (PotionEffect effect : effects) {
      result.add(new JsonObject()
                   .add("type", effect.getType().getKey().asString())
                   .add("amplifier", effect.getAmplifier())
                   .add("duration", effect.getDuration())
                   .add("ambient", effect.isAmbient())
                   .add("particles", effect.hasParticles())
                   .add("icon", effect.hasIcon()));
    }

    return result.toString();
  }

  private String equipmentJson(EntityEquipment equipment) {
    if (equipment == null) return "{}";

    return new JsonObject()
      .addRaw("main_hand", itemJson(equipment.getItemInMainHand()))
      .addRaw("off_hand", itemJson(equipment.getItemInOffHand()))
      .addRaw("helmet", itemJson(equipment.getHelmet()))
      .addRaw("chestplate", itemJson(equipment.getChestplate()))
      .addRaw("leggings", itemJson(equipment.getLeggings()))
      .addRaw("boots", itemJson(equipment.getBoots()))
      .toString();
  }

  private String itemJson(ItemStack item) {
    if (item == null || item.getType() == Material.AIR) return "null";

    JsonObject object = new JsonObject()
      .add("material", item.getType().getKey().asString())
      .add("amount", item.getAmount());

    ItemMeta meta = item.getItemMeta();
    if (meta != null) {
      if (meta.hasCustomModelData()) object.add("custom_model_data", meta.getCustomModelData());

      JsonArray pdcKeys = new JsonArray();
      meta.getPersistentDataContainer().getKeys().stream()
          .map(NamespacedKey::asString)
          .sorted()
          .forEach(pdcKeys::add);
      object.addRaw("pdc_keys", pdcKeys.toString());
    }

    JsonArray enchantments = new JsonArray();
    for (Map.Entry<org.bukkit.enchantments.Enchantment, Integer> entry : item.getEnchantments().entrySet()) {
      enchantments.add(new JsonObject()
                         .add("type", entry.getKey().getKey().asString())
                         .add("level", entry.getValue()));
    }
    object.addRaw("enchantments", enchantments.toString());

    return object.toString();
  }

  private String environmentJson(Location location) {
    JsonArray result = new JsonArray();
    int baseX = location.getBlockX();
    int baseY = location.getBlockY();
    int baseZ = location.getBlockZ();

    for (int dx = -1; dx <= 1; dx++) {
      for (int dy = -1; dy <= 1; dy++) {
        for (int dz = -1; dz <= 1; dz++) {
          Block block = location.getWorld().getBlockAt(baseX + dx, baseY + dy, baseZ + dz);
          Material type = block.getType();
          result.add(new JsonObject()
                       .add("dx", dx)
                       .add("dy", dy)
                       .add("dz", dz)
                       .add("type", type.getKey().asString())
                       .add("solid", type.isSolid())
                       .add("occluding", type.isOccluding())
                       .add("passable", block.isPassable()));
        }
      }
    }

    return result.toString();
  }

  private String characteristicsJson(PersistentDataContainer container) {
    JsonObject object = new JsonObject();
    addPdcDouble(object, container, "characters_base:health_value", "health_value");
    addPdcDouble(object, container, "characters_base:health_percent", "health_percent");
    addPdcDouble(object, container, "characters_base:regeneration_value", "regeneration_value");
    addPdcDouble(object, container, "characters_base:regeneration_percent", "regeneration_percent");
    addPdcDouble(object, container, "characters_base:damage_value", "damage_value");
    addPdcDouble(object, container, "characters_base:resistance_value", "resistance_value");
    addPdcDouble(object, container, "characters_base:critical_chance", "critical_chance");
    addPdcDouble(object, container, "characters_base:critical_damage_percent", "critical_damage_percent");
    return object.toString();
  }

  private void addPdcDouble(JsonObject object, PersistentDataContainer container, String key, String jsonKey) {
    NamespacedKey namespacedKey = NamespacedKey.fromString(key);
    if (namespacedKey == null) return;

    Double value = container.get(namespacedKey, PersistentDataType.DOUBLE);
    if (value != null) object.add(jsonKey, value);
  }

  private String flagsJson(Player player) {
    return new JsonObject()
      .add("allow_flight", player.getAllowFlight())
      .add("can_pickup_items", player.getCanPickupItems())
      .add("collidable", player.isCollidable())
      .add("visual_fire", player.isVisualFire())
      .add("fire_ticks", player.getFireTicks())
      .add("freeze_ticks", player.getFreezeTicks())
      .add("fall_distance", player.getFallDistance())
      .add("remaining_air", player.getRemainingAir())
      .add("health", player.getHealth())
      .add("absorption", player.getAbsorptionAmount())
      .add("food_level", player.getFoodLevel())
      .toString();
  }

  private static final class JsonObject {
    private final StringJoiner joiner = new StringJoiner(",", "{", "}");

    private JsonObject add(String key, String value) {
      joiner.add(quote(key) + ":" + quote(value));
      return this;
    }

    private JsonObject add(String key, Number value) {
      joiner.add(quote(key) + ":" + number(value));
      return this;
    }

    private JsonObject add(String key, boolean value) {
      joiner.add(quote(key) + ":" + value);
      return this;
    }

    private JsonObject addRaw(String key, String rawJson) {
      joiner.add(quote(key) + ":" + rawJson);
      return this;
    }

    @Override
    public String toString() {
      return joiner.toString();
    }
  }

  private static final class JsonArray {
    private final StringJoiner joiner = new StringJoiner(",", "[", "]");

    private JsonArray add(String value) {
      joiner.add(quote(value));
      return this;
    }

    private JsonArray add(JsonObject value) {
      joiner.add(value.toString());
      return this;
    }

    @Override
    public String toString() {
      return joiner.toString();
    }
  }

  private static final class PlayerDebugBuffer {
    private final Deque<MovementSample> samples = new ArrayDeque<>();
    private final Deque<DebugEvent> events = new ArrayDeque<>();
  }

  private record MovementSample(long timeMillis,
                                double x,
                                double y,
                                double z,
                                double velocityX,
                                double velocityY,
                                double velocityZ,
                                double horizontalSpeed,
                                double verticalSpeed,
                                boolean onGround,
                                boolean sprinting,
                                boolean swimming,
                                boolean flying,
                                boolean gliding,
                                boolean insideVehicle,
                                String blockBelow,
                                String blockFeet,
                                int ping,
                                double tps,
                                double mspt) {
    private JsonObject toJson(long now) {
      return new JsonObject()
        .add("age_ms", now - timeMillis)
        .add("x", x)
        .add("y", y)
        .add("z", z)
        .add("velocity_x", velocityX)
        .add("velocity_y", velocityY)
        .add("velocity_z", velocityZ)
        .add("horizontal_speed", horizontalSpeed)
        .add("vertical_speed", verticalSpeed)
        .add("on_ground", onGround)
        .add("sprinting", sprinting)
        .add("swimming", swimming)
        .add("flying", flying)
        .add("gliding", gliding)
        .add("inside_vehicle", insideVehicle)
        .add("block_below", blockBelow)
        .add("block_feet", blockFeet)
        .add("ping", ping)
        .add("tps", tps)
        .add("mspt", mspt);
    }
  }

  private record DebugEvent(long timeMillis, String type, String payloadJson) {
    private JsonObject toJson(long now) {
      return new JsonObject()
        .add("age_ms", now - timeMillis)
        .add("type", type)
        .addRaw("payload", payloadJson);
    }
  }

  private record BufferSnapshot(int samplesCount,
                                double maxHorizontalSpeed,
                                double avgHorizontalSpeed,
                                double p95HorizontalSpeed,
                                double maxVerticalSpeed,
                                int maxPing,
                                double maxMspt,
                                int groundStateChanges,
                                int blockBelowChanges,
                                boolean hadRecentVelocity,
                                boolean hadRecentTeleport,
                                int msSinceLastVelocity,
                                int msSinceLastTeleport,
                                String samplesJson,
                                String eventsJson) {
    private static BufferSnapshot empty() {
      return new BufferSnapshot(0, 0, 0, 0, 0, 0, 0, 0, 0, false, false, -1, -1, "[]", "[]");
    }

    private static BufferSnapshot from(List<MovementSample> samples, List<DebugEvent> events, long now) {
      if (samples.isEmpty() && events.isEmpty()) return empty();

      double maxHorizontalSpeed = samples.stream().mapToDouble(MovementSample::horizontalSpeed).max().orElse(0);
      double avgHorizontalSpeed = samples.stream().mapToDouble(MovementSample::horizontalSpeed).average().orElse(0);
      double p95HorizontalSpeed = percentile(samples.stream().map(MovementSample::horizontalSpeed).toList(), 0.95);
      double maxVerticalSpeed = samples.stream().mapToDouble(sample -> Math.abs(sample.verticalSpeed())).max().orElse(0);
      int maxPing = samples.stream().mapToInt(MovementSample::ping).max().orElse(0);
      double maxMspt = samples.stream().mapToDouble(MovementSample::mspt).max().orElse(0);
      int groundStateChanges = countGroundStateChanges(samples);
      int blockBelowChanges = countBlockBelowChanges(samples);

      DebugEvent lastVelocity = lastEvent(events, "velocity");
      DebugEvent lastTeleport = lastEvent(events, "teleport");

      JsonArray samplesJson = new JsonArray();
      samples.forEach(sample -> samplesJson.add(sample.toJson(now)));

      JsonArray eventsJson = new JsonArray();
      events.forEach(event -> eventsJson.add(event.toJson(now)));

      return new BufferSnapshot(
        samples.size(),
        maxHorizontalSpeed,
        avgHorizontalSpeed,
        p95HorizontalSpeed,
        maxVerticalSpeed,
        maxPing,
        maxMspt,
        groundStateChanges,
        blockBelowChanges,
        lastVelocity != null,
        lastTeleport != null,
        lastVelocity == null ? -1 : (int) (now - lastVelocity.timeMillis()),
        lastTeleport == null ? -1 : (int) (now - lastTeleport.timeMillis()),
        samplesJson.toString(),
        eventsJson.toString()
      );
    }

    private static double percentile(List<Double> values, double percentile) {
      if (values.isEmpty()) return 0;

      List<Double> sorted = new ArrayList<>(values);
      sorted.sort(Comparator.naturalOrder());
      int index = (int) Math.ceil(percentile * sorted.size()) - 1;
      return sorted.get(Math.max(0, Math.min(index, sorted.size() - 1)));
    }

    private static int countGroundStateChanges(List<MovementSample> samples) {
      if (samples.size() < 2) return 0;

      int changes = 0;
      boolean previous = samples.get(0).onGround();
      for (int i = 1; i < samples.size(); i++) {
        boolean current = samples.get(i).onGround();
        if (current != previous) changes++;
        previous = current;
      }
      return changes;
    }

    private static int countBlockBelowChanges(List<MovementSample> samples) {
      if (samples.size() < 2) return 0;

      int changes = 0;
      String previous = samples.get(0).blockBelow();
      for (int i = 1; i < samples.size(); i++) {
        String current = samples.get(i).blockBelow();
        if (!current.equals(previous)) changes++;
        previous = current;
      }
      return changes;
    }

    private static DebugEvent lastEvent(List<DebugEvent> events, String type) {
      DebugEvent result = null;
      for (DebugEvent event : events) {
        if (event.type().equals(type)) result = event;
      }
      return result;
    }
  }

  private static String number(Number value) {
    if (value == null) return "null";
    if (value instanceof Double || value instanceof Float) {
      double d = value.doubleValue();
      if (Double.isNaN(d) || Double.isInfinite(d)) return "null";
    }
    return value.toString();
  }

  private static String quote(String value) {
    if (value == null) return "null";

    StringBuilder result = new StringBuilder(value.length() + 2);
    result.append('"');
    for (int i = 0; i < value.length(); i++) {
      char c = value.charAt(i);
      switch (c) {
        case '"' -> result.append("\\\"");
        case '\\' -> result.append("\\\\");
        case '\b' -> result.append("\\b");
        case '\f' -> result.append("\\f");
        case '\n' -> result.append("\\n");
        case '\r' -> result.append("\\r");
        case '\t' -> result.append("\\t");
        default -> {
          if (c < 0x20) result.append(String.format("\\u%04x", (int) c));
